using Microsoft.AspNetCore.Builder;\nusing Microsoft.AspNetCore.Hosting;\nusing Microsoft.Extensions.DependencyInjection;\nusing Microsoft.Extensions.Hosting;\nusing Microsoft.EntityFrameworkCore;\nusing PayrollSystem.Infrastructure;\nusing Microsoft.OpenApi.Models;\n\nnamespace PayrollSystem\n{\n    public class Startup\n    {\n        public void ConfigureServices(IServiceCollection services)\n        {\n            services.AddDbContext<AppDbContext>(options =>\n                options.UseNpgsql("Host=localhost;Database=payroll;Username=postgres;Password=password"));\n\n            services.AddControllers();\n            services.AddSwaggerGen(c =>\n            {\n                c.SwaggerDoc("v1", new OpenApiInfo { Title = "Payroll System API", Version = "v1" });\n            });\n        }\n\n        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)\n        {\n            if (env.IsDevelopment())\n            {\n                app.UseDeveloperExceptionPage();\n            }\n\n            app.UseHttpsRedirection();\n            app.UseRouting();\n            app.UseAuthorization();\n\n            app.UseEndpoints(endpoints =>\n            {\n                endpoints.MapControllers();\n            });\n\n            app.UseSwagger();\n            app.UseSwaggerUI(c =>\n            {\n                c.SwaggerEndpoint("/swagger/v1/swagger.json", "Payroll System API V1");\n            });\n        }\n    }\n}